  private EditText field(String h){EditText e=new EditText(this);e.setHint(h);e.setContentDescription(h);root.addView(e,new LinearLayout.LayoutParams(-1,-2));return e;}private Button button(String s,View.OnClickListener l){Button b=new Button(this);b.setText(s);b.setAllCaps(false);b.setOnClickListener(l);root.addView(b);return b;}private void heading(String s){TextView v=new TextView(this);v.setText(s);v.setTextSize(21);v.setTypeface(null,1);v.setPadding(0,28,0,8);root.addView(v);}
  private void build(){ScrollView sc=new ScrollView(this);root=new LinearLayout(this);root.setOrientation(LinearLayout.VERTICAL);root.setPadding(36,30,36,60);sc.addView(root);setContentView(sc);TextView title=new TextView(this);title.setText("YNX Resource Market");title.setTextSize(30);title.setTextColor(Color.rgb(0,47,167));title.setTypeface(null,1);root.addView(title);Spinner locale=new Spinner(this);locale.setAdapter(new ArrayAdapter<>(this,android.R.layout.simple_spinner_dropdown_item,names));String saved=getPreferences(0).getString("locale",Locale.getDefault().toLanguageTag());int p=0;for(int i=0;i<codes.length;i++)if(saved.startsWith(codes[i]))p=i;locale.setSelection(p);root.addView(locale);boundary=new TextView(this);boundary.setTextSize(17);boundary.setPadding(0,24,0,24);root.addView(boundary);locale.setOnItemSelectedListener(new android.widget.AdapterView.OnItemSelectedListener(){public void onNothingSelected(android.widget.AdapterView<?> p){}public void onItemSelected(android.widget.AdapterView<?> p,View v,int i,long x){getPreferences(0).edit().putString("locale",codes[i]).apply();boundary.setText(boundaries[i]);root.setLayoutDirection(codes[i].equals("ar")?View.LAYOUT_DIRECTION_RTL:View.LAYOUT_DIRECTION_LTR);}});heading("Canonical YNX Wallet");TextView auth=new TextView(this);auth.setText("Authorization is product, device, callback, scope and expiry bound. The Wallet approval still requires a fresh central challenge signed by this app's non-exportable P-256 key.");auth.setTextSize(16);auth.setPadding(0,0,0,12);root.addView(auth);button("Open canonical YNX Wallet",v->authorize());heading("Authoritative market");account=field("YNX account (ynx1…)");button("Load resource balances",v->request("GET","/api/authority/balances/"+Uri.encode(account.getText().toString()),null));button("Load price quote",v->request("GET","/api/authority/quote",null));kind=new Spinner(this);kind.setAdapter(new ArrayAdapter<>(this,android.R.layout.simple_spinner_dropdown_item,new String[]{"rental","delegation","sponsorship"}));root.addView(kind);idempotency=field("Idempotency key");payload=field("Exact Wallet-reviewed signed payload JSON");payload.setMinLines(5);payload.setSingleLine(false);button("Submit signed purchase intent",v->intent(false));button("Retry exact failed intent",v->intent(true));status=new TextView(this);status.setPadding(0,28,0,20);status.setText("No quote, capacity or settlement result loaded.");status.setContentDescription("Resource Market status");root.addView(status);}
  private static String b64(byte[] value){return Base64.getUrlEncoder().withoutPadding().encodeToString(value);}private static String fixed(java.math.BigInteger n){byte[] raw=n.toByteArray(),out=new byte[32];System.arraycopy(raw,Math.max(0,raw.length-32),out,Math.max(0,32-raw.length),Math.min(32,raw.length));return b64(out);}
  private void authorize(){try{KeyStore ks=KeyStore.getInstance("AndroidKeyStore");ks.load(null);if(ks.containsAlias("ynx-resource-wallet-v1"))ks.deleteEntry("ynx-resource-wallet-v1");KeyPairGenerator g=KeyPairGenerator.getInstance("EC","AndroidKeyStore");g.initialize(new android.security.keystore.KeyGenParameterSpec.Builder("ynx-resource-wallet-v1",android.security.keystore.KeyProperties.PURPOSE_SIGN).setAlgorithmParameterSpec(new ECGenParameterSpec("secp256r1")).setDigests(android.security.keystore.KeyProperties.DIGEST_SHA256).build());KeyPair pair=g.generateKeyPair();ECPublicKey pub=(ECPublicKey)pair.getPublic();byte[] compressed=new byte[33],x=Base64.getUrlDecoder().decode(fixed(pub.getW().getAffineX()));compressed[0]=(byte)(pub.getW().getAffineY().testBit(0)?3:2);System.arraycopy(x,0,compressed,1,32);byte[] nonceBytes=new byte[24];new SecureRandom().nextBytes(nonceBytes);Instant now=Instant.now();String nonce=b64(nonceBytes),deviceKey=b64(compressed),issued=now.toString(),expires=now.plusSeconds(300).toString(),scopes="[\"account:read\",\"resource:analytics\",\"resource:capacity:read\",\"resource:dispute\",\"resource:history\",\"resource:intent\",\"resource:quote\"]",request="{\"bundleId\":\"com.ynxweb4.resource\",\"callback\":\"ynxresource://wallet-auth/callback\",\"chainId\":\"ynx_6423-1\",\"expiresAt\":"+JSONObject.quote(expires)+",\"issuedAt\":"+JSONObject.quote(issued)+",\"nonce\":"+JSONObject.quote(nonce)+",\"productClientId\":\"ynx-resource-market-v1\",\"productDeviceAlgorithm\":\"p256-sha256\",\"productDeviceKey\":"+JSONObject.quote(deviceKey)+",\"purpose\":\"Read authoritative capacity and submit one Wallet-reviewed resource intent\",\"requestingProduct\":\"resource-market\",\"scopes\":"+scopes+",\"version\":\"1\"}";store.put("pendingRequest",request);store.put("device",deviceKey);startActivity(new Intent(Intent.ACTION_VIEW,Uri.parse("ynxwallet://authorize?request="+b64(request.getBytes(StandardCharsets.UTF_8)))));show("Review the exact product, callback, device key, scopes and five-minute expiry in YNX Wallet.");}catch(Exception e){show("Canonical Wallet request unavailable. No local session was created.");}}
  private void intent(boolean retry){try{if(idempotency.getText().length()==0)idempotency.setText(UUID.randomUUID().toString());JSONObject signed=new JSONObject(payload.getText().toString());JSONObject j=new JSONObject().put("kind",kind.getSelectedItem().toString()).put("idempotencyKey",idempotency.getText()).put("payload",signed);String path=retry?"/api/authority/intents/"+Uri.encode(intentId)+"/retry":"/api/authority/intents";if(retry&&intentId.isEmpty()){show("No failed intent is available. Exact retry is required.");return;}request("POST",path,j);}catch(Exception e){show("Signed payload must be valid JSON. No transaction was submitted.");}}
  private void request(String method,String path,JSONObject body){show("Loading authoritative response…");Executors.newSingleThreadExecutor().execute(()->{try{byte[] raw=body==null?new byte[0]:body.toString().getBytes(StandardCharsets.UTF_8);HttpURLConnection c=(HttpURLConnection)new URL(BuildConfig.GATEWAY_BASE_URL+path).openConnection();c.setRequestMethod(method);c.setConnectTimeout(5000);c.setReadTimeout(8000);c.setRequestProperty("Content-Type","application/json");String binding=store.get("session"),deviceKey=store.get("device");if(binding!=null&&deviceKey!=null)c.setRequestProperty("X-YNX-Product-Session-Proof",productProof(method,path,raw,binding,deviceKey));if(body!=null){c.setDoOutput(true);c.getOutputStream().write(raw);}int code=c.getResponseCode();String text=read(code<400?c.getInputStream():c.getErrorStream());if(path.contains("/intents")&&!path.contains("retry")){try{intentId=new JSONObject(text).getJSONObject("intent").getString("id");}catch(Exception ignored){}}show("HTTP "+code+"\n"+text+"\nA quote is not settlement; no asset movement is asserted.");}catch(Exception e){show("Unavailable: "+e.getMessage()+"\nNo quote, capacity, settlement or asset action was substituted.");}});}
  private String productProof(String method,String path,byte[] body,String binding,String deviceKey)throws Exception{KeyStore ks=KeyStore.getInstance("AndroidKeyStore");ks.load(null);PrivateKey privateKey=(PrivateKey)ks.getKey("ynx-resource-wallet-v1",null);if(privateKey==null)throw new SecurityException("device proof key unavailable");Instant now=Instant.now(),sessionExpiry=Instant.parse(store.get("sessionExpiresAt"));Instant expiry=now.plusSeconds(30).isBefore(sessionExpiry)?now.plusSeconds(30):sessionExpiry;DateTimeFormatter f=DateTimeFormatter.ofPattern("yyyy-MM-dd'T'HH:mm:ss.SSS'Z'").withZone(ZoneOffset.UTC);byte[] nonce=new byte[24];new SecureRandom().nextBytes(nonce);String digest=hex(MessageDigest.getInstance("SHA-256").digest(body));JSONObject unsigned=new JSONObject().put("bodyDigest",digest).put("bundleId","com.ynxweb4.resource").put("expiresAt",f.format(expiry)).put("issuedAt",f.format(now)).put("method",method).put("nonce",b64(nonce)).put("path",path).put("productClientId","ynx-resource-market-v1").put("productDeviceKey",deviceKey).put("sessionBinding",binding).put("version","1");Signature signer=Signature.getInstance("SHA256withECDSA");signer.initSign(privateKey);signer.update(("YNX_PRODUCT_SESSION_HTTP_PROOF_V1\n"+canonical(unsigned)).getBytes(StandardCharsets.UTF_8));JSONObject proof=new JSONObject(unsigned.toString()).put("signature",b64(signer.sign()));return b64(proof.toString().getBytes(StandardCharsets.UTF_8));}
  private static String hex(byte[] raw){StringBuilder s=new StringBuilder(raw.length*2);for(byte b:raw)s.append(String.format(Locale.ROOT,"%02x",b&255));return s.toString();}
  private String read(InputStream in)throws Exception{if(in==null)return"";ByteArrayOutputStream o=new ByteArrayOutputStream();byte[] b=new byte[2048];int n;while((n=in.read(b))>0&&o.size()<262144)o.write(b,0,n);return o.toString("UTF-8");}private int activeLocale(){String saved=getPreferences(0).getString("locale",Locale.getDefault().toLanguageTag());for(int i=0;i<codes.length;i++)if(saved.startsWith(codes[i]))return i;return 0;}private void show(String s){runOnUiThread(()->{int i=activeLocale();status.setContentDescription(statusLabels[i]);status.setText(s.startsWith("Unavailable:")?unavailable[i]+"\n"+s.substring("Unavailable:".length()).trim():s);});}
  private void callback(Intent i){if(i==null||i.getData()==null)return;Uri u=i.getData();if(!"ynxresource".equals(u.getScheme())||!"wallet-auth".equals(u.getHost())||!"/callback".equals(u.getPath())||u.getQueryParameterNames().size()!=1||!u.getQueryParameterNames().contains("response")){show("Wallet callback rejected: route or fields do not match the registered callback. No session was created.");return;}try{String encoded=u.getQueryParameter("response"),pending=store.get("pendingRequest");if(encoded==null||encoded.length()>12288||pending==null)throw new SecurityException("missing callback state");JSONObject request=new JSONObject(pending),approval=new JSONObject(new String(Base64.getUrlDecoder().decode(encoded),StandardCharsets.UTF_8));for(String key:new String[]{"nonce","chainId","requestingProduct","productClientId","bundleId","productDeviceAlgorithm","productDeviceKey","callback","purpose"})if(!request.getString(key).equals(approval.getString(key)))throw new SecurityException("approval binding mismatch");if(!request.getJSONArray("scopes").toString().equals(approval.getJSONArray("grantedScopes").toString()))throw new SecurityException("approval scope mismatch");completeWallet(request,approval);}catch(Exception e){show("Wallet callback rejected: malformed or mismatched authorization response. No session was created.");}}
  private void completeWallet(JSONObject request,JSONObject approval){show("Wallet approval received. Requesting a bound central device challenge…");Executors.newSingleThreadExecutor().execute(()->{try{JSONObject challenge=postJSON("/api/auth/session/challenge",new JSONObject().put("authorizationRequest",request).put("walletApproval",approval));if(!request.getString("productDeviceKey").equals(challenge.getString("productDeviceKey"))||!request.getString("productClientId").equals(challenge.getString("productClientId"))||!request.getString("bundleId").equals(challenge.getString("bundleId")))throw new SecurityException("challenge binding mismatch");KeyStore ks=KeyStore.getInstance("AndroidKeyStore");ks.load(null);PrivateKey privateKey=(PrivateKey)ks.getKey("ynx-resource-wallet-v1",null);if(privateKey==null)throw new SecurityException("device key unavailable");Signature signer=Signature.getInstance("SHA256withECDSA");signer.initSign(privateKey);signer.update(("YNX_PRODUCT_SESSION_CHALLENGE_V1\n"+canonical(challenge)).getBytes(StandardCharsets.UTF_8));String signature=b64(signer.sign());JSONObject completion=new JSONObject().put("authorizationRequest",request).put("walletApproval",approval).put("gatewayCompletion",new JSONObject().put("challenge",challenge).put("deviceSignature",signature)),session=postJSON("/api/auth/session/complete",completion);if(!"wallet-auth-v1".equals(session.getString("verifierVersion"))||!request.getString("productDeviceKey").equals(session.getString("productDeviceKey")))throw new SecurityException("session binding mismatch");store.put("session",session.getString("sessionBinding"));store.put("sessionExpiresAt",session.getString("expiresAt"));store.remove("pendingRequest");show("Canonical Wallet session verified. Authority requests use a fresh signed, replay-resistant proof.");}catch(Exception e){show("Canonical Wallet completion unavailable or rejected. No local session or settlement was created.");}});}
  private JSONObject postJSON(String path,JSONObject body)throws Exception{HttpURLConnection c=(HttpURLConnection)new URL(BuildConfig.GATEWAY_BASE_URL+path).openConnection();c.setRequestMethod("POST");c.setConnectTimeout(5000);c.setReadTimeout(8000);c.setRequestProperty("Content-Type","application/json");c.setDoOutput(true);c.getOutputStream().write(body.toString().getBytes(StandardCharsets.UTF_8));int code=c.getResponseCode();String text=read(code<400?c.getInputStream():c.getErrorStream());if(code/100!=2)throw new IOException("HTTP "+code);return new JSONObject(text);}
  private static String canonical(Object value)throws Exception{if(value==null||value==JSONObject.NULL)return"null";if(value instanceof JSONObject){JSONObject o=(JSONObject)value;ArrayList<String> keys=new ArrayList<>();Iterator<String> it=o.keys();while(it.hasNext())keys.add(it.next());Collections.sort(keys);StringBuilder s=new StringBuilder("{");for(int i=0;i<keys.size();i++){if(i>0)s.append(',');String k=keys.get(i);s.append(JSONObject.quote(k)).append(':').append(canonical(o.get(k)));}return s.append('}').toString();}if(value instanceof JSONArray){JSONArray a=(JSONArray)value;StringBuilder s=new StringBuilder("[");for(int i=0;i<a.length();i++){if(i>0)s.append(',');s.append(canonical(a.get(i)));}return s.append(']').toString();}if(value instanceof String)return JSONObject.quote((String)value);if(value instanceof Boolean)return value.toString();if(value instanceof Number){double n=((Number)value).doubleValue();if(!Double.isFinite(n))throw new JSONException("non-finite number");return value.toString();}throw new JSONException("unsupported canonical value");}
  static final class SecureStore{private final android.content.SharedPreferences p;SecureStore(Context c){p=c.getSharedPreferences("secure",0);}private SecretKey key()throws Exception{KeyStore k=KeyStore.getInstance("AndroidKeyStore");k.load(null);if(!k.containsAlias("ynx-resource-session")){KeyGenerator g=KeyGenerator.getInstance("AES","AndroidKeyStore");g.init(new android.security.keystore.KeyGenParameterSpec.Builder("ynx-resource-session",3).setBlockModes("GCM").setEncryptionPaddings("NoPadding").build());g.generateKey();}return((KeyStore.SecretKeyEntry)k.getEntry("ynx-resource-session",null)).getSecretKey();}void put(String n,String v)throws Exception{Cipher c=Cipher.getInstance("AES/GCM/NoPadding");c.init(Cipher.ENCRYPT_MODE,key());byte[] out=c.doFinal(v.getBytes(StandardCharsets.UTF_8));p.edit().putString(n,Base64.getEncoder().encodeToString(c.getIV())+"."+Base64.getEncoder().encodeToString(out)).apply();}void remove(String n){p.edit().remove(n).apply();}String get(String n){try{String v=p.getString(n,null);if(v==null)return null;String[] x=v.split("\\.");Cipher c=Cipher.getInstance("AES/GCM/NoPadding");c.init(Cipher.DECRYPT_MODE,key(),new GCMParameterSpec(128,Base64.getDecoder().decode(x[0])));return new String(c.doFinal(Base64.getDecoder().decode(x[1])),StandardCharsets.UTF_8);}catch(Exception e){return null;}}}
